import TrackItem from './TrackItem';

interface Track {
  id: string;
  title: string;
  artist: string;
  album: string;
  duration: string;
}

const TrackList = ({ tracks, onTrackSelect }: { tracks: Track[]; onTrackSelect: (id: string) => void }) => (
  <div className="bg-gray-900 p-6 rounded-xl shadow-md">
    {tracks.length === 0 ? (
      <p className="text-gray-400">No tracks available. Start exploring music!</p>
    ) : (
      <ul className="space-y-4">
        {tracks.map(track => (
          <TrackItem key={track.id} track={track} onSelect={onTrackSelect} />
        ))}
      </ul>
    )}
  </div>
);

export default TrackList;

